import React from 'react';

const MovieDetails = ({ data }) => {
  if (!data) return null;

  return (
    <div className="movie-details-hero">
      <div 
        className="hero-backdrop" 
        style={{ backgroundImage: `url(${data.backdrop})` }}
      ></div>
      <div className="hero-overlay"></div>

      <div className="hero-content">
        <h1 className="hero-title">{data.title}</h1>

        <div className="hero-meta">
          <span>{data.year}</span> | 
          <span>{data.genres.join(', ')}</span> | 
          <span>{data.runtime}</span> | 
          <span>Language: {data.language}</span>
        </div>

        <div className="hero-main-row">
          <div className="hero-poster">
            <img src={data.poster} alt={data.title} />
          </div>

          <div className="hero-info">
            <p className="hero-crew"><strong>Written by</strong> {data.writer}</p>
            <p className="hero-crew"><strong>Cast:</strong> {data.cast}</p>
            <p className="hero-synopsis">{data.synopsis}</p>
          </div>
        </div>

        {data.stills && data.stills.length > 0 && (
          <div className="hero-stills">
            {data.stills.map((still, idx) => (
              <div 
                key={idx} 
                className="still-img" 
                style={{ backgroundImage: `url(${still})` }}
              ></div>
            ))}
          </div>
        )}

        {data.quote && (
          <div className="hero-quote">
            "{data.quote}"
          </div>
        )}
      </div>
    </div>
  );
};

export default MovieDetails;
